import React from 'react';
import Icon from '../../../components/AppIcon';

const CostBreakdown = ({ bookingDetails }) => {
  const formatPrice = (price) => {
    return price?.toFixed(2);
  };

  // Calculate new commission structure
  const platformFee = bookingDetails?.equipmentTotal * 0.12; // 12% platform commission
  const paymentFee = (bookingDetails?.equipmentTotal * 0.015) + 0.25; // 1.5% + 0.25€ payment fees
  const totalFees = platformFee + paymentFee;
  const newTotalAmount = bookingDetails?.equipmentTotal + totalFees + (bookingDetails?.insuranceFee || 0);

  return (
    <div className="space-y-3">
      {/* Equipment Price */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="Package" size={18} className="text-muted-foreground" />
          <span className="text-sm text-foreground">
            Location équipement ({bookingDetails?.rentalDays} jour{bookingDetails?.rentalDays > 1 ? 's' : ''})
          </span>
        </div>
        <span className="font-medium text-foreground">
          {formatPrice(bookingDetails?.equipmentTotal)} €
        </span>
      </div>

      {/* Platform Commission */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="Percent" size={18} className="text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Commission plateforme (12%)
          </span>
        </div>
        <span className="text-sm text-muted-foreground">
          {formatPrice(platformFee)} €
        </span>
      </div>

      {/* Payment Fees */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="CreditCard" size={18} className="text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Frais de paiement (1,5% + 0,25 €)
          </span>
        </div>
        <span className="text-sm text-muted-foreground">
          {formatPrice(paymentFee)} €
        </span>
      </div>

      {/* Insurance Fee */}
      {bookingDetails?.includeInsurance && bookingDetails?.insuranceFee > 0 && (
        <div className="flex justify-between items-center py-2">
          <div className="flex items-center gap-2">
            <Icon name="ShieldCheck" size={18} className="text-success" />
            <span className="text-sm text-success-foreground">
              Assurance tous risques
            </span>
          </div>
          <span className="text-sm text-success-foreground">
            {formatPrice(bookingDetails?.insuranceFee)} €
          </span>
        </div>
      )}

      {/* Divider */}
      <div className="border-t border-border my-3" />

      {/* Total to Pay */}
      <div className="flex justify-between items-center py-2">
        <span className="text-lg font-semibold text-foreground">
          Total à payer
        </span>
        <span className="text-xl font-bold text-primary">
          {formatPrice(newTotalAmount)} €
        </span>
      </div>

      {/* Caution Note */}
      <div className="mt-4 p-3 bg-warning/10 rounded-md border border-warning/20">
        <div className="flex items-start gap-2">
          <Icon name="AlertCircle" size={16} className="text-warning flex-shrink-0 mt-0.5" />
          <div className="text-xs text-muted-foreground">
            <p className="font-medium text-foreground mb-1">
              + Caution demandée : {formatPrice(bookingDetails?.cautionAmount)} €
            </p>
            <p className="mb-1">
              <strong>Séparé du paiement ci-dessus.</strong> La caution est une empreinte bancaire temporaire. Elle ne sera prélevée qu'en cas de dommage ou non-restitution.
            </p>
            <p>
              L'empreinte sera libérée sous 48h après la restitution de l'équipement.
            </p>
          </div>
        </div>
      </div>

      {/* Payment Info */}
      <div className="mt-4 p-3 bg-muted/50 rounded-md">
        <p className="text-xs text-muted-foreground">
          <Icon name="Info" size={14} className="inline mr-1" />
          Le paiement sera traité de manière sécurisée. Vous recevrez une confirmation par e-mail.
        </p>
      </div>
    </div>
  );
};

export default CostBreakdown;
