import React, { useEffect, useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';
import toast from 'react-hot-toast';

import Header from '../../components/navigation/Header';
import Footer from '../../components/Footer';
import Button from '../../components/ui/Button';
import Icon from '../../components/AppIcon';
import PaymentForm from './components/PaymentForm';
import CostBreakdown from './components/CostBreakdown';
import SecurityBadges from './components/SecurityBadges';
import reservationService from '../../services/reservationService';
import storageService from '../../services/storageService';
import { useAuth } from '../../contexts/AuthContext';
import { supabase } from '../../lib/supabase';

const PENDING_PAYMENT_CONTEXT_STORAGE_KEY = 'pending_payment_checkout_context_v1';

const toDateOrNull = (value) => {
  if (!value) return null;
  const date = value instanceof Date ? value : new Date(value);
  return Number.isNaN(date?.getTime()) ? null : date;
};

const normalizeStateBookingData = (stateEquipment, stateBookingDetails) => {
  if (!stateEquipment || !stateBookingDetails) return null;

  return {
    equipment: stateEquipment,
    bookingDetails: {
      ...stateBookingDetails,
      startDate: toDateOrNull(stateBookingDetails?.startDate),
      endDate: toDateOrNull(stateBookingDetails?.endDate)
    }
  };
};

const normalizeFromReservation = (reservation) => {
  if (!reservation) return null;

  const annoncePhotos = Array?.isArray(reservation?.annonce?.photos) ? reservation?.annonce?.photos : [];
  const resolvedPhotos = storageService?.getAnnoncePhotoUrls(annoncePhotos);
  const firstPhoto = resolvedPhotos?.[0] || annoncePhotos?.[0] || '/assets/images/no_image.png';

  const startDate = toDateOrNull(reservation?.start_date);
  const endDate = toDateOrNull(reservation?.end_date);
  const rentalDays = startDate && endDate
    ? Math.max(1, Math.ceil((endDate - startDate) / (1000 * 60 * 60 * 24)))
    : 0;

  const totalAmount = Number(reservation?.total_price ?? 0) || 0;
  const cautionAmount = Number(reservation?.annonce?.caution ?? reservation?.caution_amount ?? 0) || 0;
  const equipmentTotal = totalAmount; // fallback: exact detail may not be persisted separately

  return {
    equipment: {
      id: reservation?.annonce_id,
      title: reservation?.annonce?.titre || 'Annonce',
      category: reservation?.annonce?.categorie || reservation?.annonce?.category || '-',
      dailyPrice: Number(reservation?.annonce?.prix_jour ?? 0) || 0,
      images: [{ url: firstPhoto, alt: reservation?.annonce?.titre || 'Photo annonce' }],
      owner: {
        pseudonym: reservation?.owner?.pseudo || 'Proprietaire',
        avatar: reservation?.owner?.avatar_url || '/assets/images/no_image.png',
        avatarAlt: `Avatar de ${reservation?.owner?.pseudo || 'proprietaire'}`,
        rating: null,
        reviewCount: null
      }
    },
    bookingDetails: {
      reservationId: reservation?.id,
      startDate,
      endDate,
      rentalDays,
      equipmentTotal,
      platformCommission: 0,
      insuranceFee: Number(reservation?.insurance_fee ?? 0) || 0,
      totalAmount,
      cautionAmount,
      includeInsurance: Boolean(reservation?.insurance_fee),
      message: reservation?.message || ''
    }
  };
};

const savePendingPaymentContext = (pageData) => {
  if (typeof window === 'undefined' || !window?.sessionStorage || !pageData) return;

  try {
    window.sessionStorage.setItem(
      PENDING_PAYMENT_CONTEXT_STORAGE_KEY,
      JSON.stringify({
        pageData,
        savedAt: new Date().toISOString()
      })
    );
  } catch (error) {
    console.warn('Impossible de sauvegarder le contexte de paiement localement:', error);
  }
};

const loadPendingPaymentContext = () => {
  if (typeof window === 'undefined' || !window?.sessionStorage) return null;

  try {
    const raw = window.sessionStorage.getItem(PENDING_PAYMENT_CONTEXT_STORAGE_KEY);
    if (!raw) return null;

    const parsed = JSON.parse(raw);
    const pageData = normalizeStateBookingData(parsed?.pageData?.equipment, parsed?.pageData?.bookingDetails);
    return pageData || null;
  } catch (error) {
    console.warn('Impossible de relire le contexte de paiement local:', error);
    return null;
  }
};

const clearPendingPaymentContext = () => {
  if (typeof window === 'undefined' || !window?.sessionStorage) return;
  try {
    window.sessionStorage.removeItem(PENDING_PAYMENT_CONTEXT_STORAGE_KEY);
  } catch (error) {
    console.warn('Impossible de nettoyer le contexte de paiement local:', error);
  }
};

const PaymentProcessing = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [loading, setLoading] = useState(false);
  const [contextLoading, setContextLoading] = useState(true);
  const [contextError, setContextError] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('new-card');
  const [pageData, setPageData] = useState(null);
  const stripeCheckoutEnabled = Boolean(import.meta.env?.VITE_STRIPE_PUBLISHABLE_KEY);

  const paymentQueryParams = useMemo(() => {
    const params = new URLSearchParams(location?.search || '');
    return {
      reservationId: params?.get('reservationId'),
      stripeStatus: params?.get('stripeStatus'),
      stripeSessionId: params?.get('session_id')
    };
  }, [location?.search]);

  const reservationIdFromQuery = paymentQueryParams?.reservationId;
  const stripeStatusFromQuery = paymentQueryParams?.stripeStatus;
  const stripeSessionIdFromQuery = paymentQueryParams?.stripeSessionId;

  useEffect(() => {
    let isMounted = true;

    const loadContext = async () => {
      try {
        setContextLoading(true);
        setContextError('');

        const fromState = normalizeStateBookingData(location?.state?.equipment, location?.state?.bookingDetails);
        if (fromState) {
          if (!isMounted) return;
          setPageData(fromState);
          return;
        }

        if (!reservationIdFromQuery) {
          const fromSessionStorage = loadPendingPaymentContext();
          if (fromSessionStorage) {
            if (!isMounted) return;
            setPageData(fromSessionStorage);
            return;
          }

          if (!isMounted) return;
          setPageData(null);
          setContextError('Aucune reservation a payer n a ete trouvee.');
          return;
        }

        const { data, error } = await reservationService?.getReservationById(reservationIdFromQuery);
        if (error) throw error;
        if (!data) {
          if (!isMounted) return;
          setPageData(null);
          setContextError('Reservation introuvable.');
          return;
        }

        if (user?.id && data?.renter_id && data?.renter_id !== user?.id) {
          if (!isMounted) return;
          setPageData(null);
          setContextError("Vous n'avez pas acces a cette reservation.");
          return;
        }

        if (!isMounted) return;
        setPageData(normalizeFromReservation(data));
      } catch (error) {
        console.error('Erreur de chargement paiement:', error);
        if (!isMounted) return;
        setPageData(null);
        setContextError(error?.message || 'Impossible de charger cette page de paiement.');
      } finally {
        if (isMounted) setContextLoading(false);
      }
    };

    loadContext();

    return () => {
      isMounted = false;
    };
  }, [location?.state, reservationIdFromQuery, user?.id]);

  useEffect(() => {
    if (!stripeStatusFromQuery) return;

    if (stripeStatusFromQuery === 'success') {
      toast?.success('Paiement Stripe test termine. Confirmation metier/backend a finaliser sur ce parcours.');
      return;
    }

    if (stripeStatusFromQuery === 'cancel') {
      toast?.('Paiement annule sur Stripe.');
    }
  }, [stripeStatusFromQuery]);

  useEffect(() => {
    if (!stripeStatusFromQuery || !pageData) return;
    clearPendingPaymentContext();
  }, [stripeStatusFromQuery, pageData]);

  const equipment = pageData?.equipment || null;
  const bookingDetails = pageData?.bookingDetails || null;
  const savedCards = [];

  const handlePayment = async () => {
    if (!equipment || !bookingDetails) {
      toast?.error('Contexte de paiement introuvable.');
      return;
    }

    if (!stripeCheckoutEnabled) {
      toast?.error("Configuration Stripe test absente (VITE_STRIPE_PUBLISHABLE_KEY).");
      return;
    }

    setLoading(true);

    try {
      savePendingPaymentContext({ equipment, bookingDetails });

      const returnBaseUrl = `${window?.location?.origin || ''}/traitement-paiement`;

      const { data, error } = await supabase.functions.invoke('create-stripe-checkout-session', {
        body: {
          returnBaseUrl,
          reservationId: bookingDetails?.reservationId || reservationIdFromQuery || null,
          equipment: {
            id: equipment?.id || null,
            title: equipment?.title || 'Reservation',
            dailyPrice: Number(equipment?.dailyPrice || 0) || 0
          },
          bookingDetails: {
            startDate: bookingDetails?.startDate ? new Date(bookingDetails.startDate).toISOString() : null,
            endDate: bookingDetails?.endDate ? new Date(bookingDetails.endDate).toISOString() : null,
            rentalDays: Number(bookingDetails?.rentalDays || 0) || 0,
            totalAmount: Number(bookingDetails?.totalAmount || 0) || 0,
            cautionAmount: Number(bookingDetails?.cautionAmount || 0) || 0
          }
        }
      });

      if (error) {
        throw error;
      }

      if (!data?.url) {
        throw new Error('Session Stripe creee sans URL de redirection.');
      }

      window.location.assign(data.url);
      return;
    } catch (error) {
      console.error('Erreur lancement paiement Stripe:', error);
      toast?.error(error?.message || 'Impossible de lancer le paiement Stripe.');
    } finally {
      setLoading(false);
    }
  };

  if (contextLoading) {
    return (
      <div className="min-h-screen flex flex-col bg-surface">
        <Header />
        <main className="flex-1 py-8 md:py-12">
          <div className="container mx-auto px-4 max-w-4xl">
            <div className="bg-white rounded-lg shadow-elevation-2 p-6">
              <div className="flex items-center gap-3 text-muted-foreground">
                <Icon name="Loader2" size={20} className="animate-spin" />
                <span>Chargement du recapitulatif de paiement...</span>
              </div>
            </div>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  if (!equipment || !bookingDetails) {
    return (
      <div className="min-h-screen flex flex-col bg-surface">
        <Header />
        <main className="flex-1 py-8 md:py-12">
          <div className="container mx-auto px-4 max-w-4xl">
            <div className="bg-white rounded-lg shadow-elevation-2 p-6 space-y-4">
              <div className="flex items-start gap-3 text-destructive">
                <Icon name="AlertCircle" size={20} className="mt-0.5" />
                <div>
                  <p className="font-medium">{contextError || 'Impossible de preparer le paiement.'}</p>
                  <p className="text-sm text-muted-foreground mt-1">
                    Revenez a la reservation puis relancez le parcours.
                  </p>
                </div>
              </div>
              <Button variant="outline" onClick={() => navigate('/accueil-recherche')}>
                Retour a la recherche
              </Button>
            </div>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-surface">
      <Header />

      <main className="flex-1 py-8 md:py-12">
        <div className="container mx-auto px-4 max-w-6xl">
          <div className="mb-6 md:mb-8">
            <button
              onClick={() => navigate(-1)}
              className="flex items-center gap-2 text-muted-foreground hover:text-foreground transition-colors mb-4"
            >
              <Icon name="ArrowLeft" size={20} />
              <span>Retour</span>
            </button>
            <h1 className="text-h2 md:text-h1 font-heading text-foreground">
              Paiement securise
            </h1>
            <p className="text-muted-foreground mt-2">
              Finalisez votre reservation en toute securite.
            </p>
          </div>

          {stripeStatusFromQuery === 'success' && (
            <div className="bg-success/10 border border-success/20 rounded-lg p-4 mb-6">
              <div className="flex gap-3">
                <Icon name="CheckCircle" size={20} className="text-success flex-shrink-0 mt-0.5" />
                <div>
                  <p className="font-medium text-foreground mb-1">Paiement Stripe test termine</p>
                  <p className="text-sm text-muted-foreground">
                    Le retour Stripe est bien branche. La mise a jour automatique de la reservation (statut/paiement) doit encore etre finalisee sur ce parcours.
                    {stripeSessionIdFromQuery ? ` Session: ${stripeSessionIdFromQuery}` : ''}
                  </p>
                </div>
              </div>
            </div>
          )}

          {stripeStatusFromQuery === 'cancel' && (
            <div className="bg-warning/10 border border-warning/20 rounded-lg p-4 mb-6">
              <div className="flex gap-3">
                <Icon name="AlertTriangle" size={20} className="text-warning flex-shrink-0 mt-0.5" />
                <div>
                  <p className="font-medium text-foreground mb-1">Paiement annule</p>
                  <p className="text-sm text-muted-foreground">
                    Vous pouvez relancer le paiement quand vous voulez.
                  </p>
                </div>
              </div>
            </div>
          )}

          <div className={`${stripeCheckoutEnabled ? 'bg-success/10 border-success/20' : 'bg-warning/10 border-warning/20'} border rounded-lg p-4 mb-6`}>
            <div className="flex gap-3">
              <Icon
                name={stripeCheckoutEnabled ? 'CheckCircle' : 'AlertTriangle'}
                size={20}
                className={`${stripeCheckoutEnabled ? 'text-success' : 'text-warning'} flex-shrink-0 mt-0.5`}
              />
              <div>
                <p className="font-medium text-foreground mb-1">
                  {stripeCheckoutEnabled ? 'Stripe test branche (Checkout)' : 'Integration paiement en cours de branchement'}
                </p>
                <p className="text-sm text-muted-foreground">
                  {stripeCheckoutEnabled
                    ? "Le bouton de paiement redirige vers Stripe en mode test. La confirmation metier (mise a jour reservation/paiement via webhook) reste a finaliser."
                    : "Cette page affiche vos vraies informations de reservation, mais la confirmation de paiement Stripe n'est pas encore reliee au backend sur ce parcours."}
                </p>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-white rounded-lg shadow-elevation-2 p-6">
                <div className="flex items-center gap-3 mb-4">
                  <Icon name="FileText" size={24} className="text-primary" />
                  <h2 className="text-h4 font-heading text-foreground">
                    Recapitulatif de la reservation
                  </h2>
                </div>

                <div className="space-y-4">
                  <div className="flex gap-4 pb-4 border-b border-border">
                    <img
                      src={equipment?.images?.[0]?.url || '/assets/images/no_image.png'}
                      alt={equipment?.images?.[0]?.alt || 'Photo annonce'}
                      className="w-24 h-24 object-cover rounded-md"
                    />
                    <div className="flex-1">
                      <h3 className="font-semibold text-foreground">{equipment?.title}</h3>
                      <p className="text-sm text-muted-foreground mt-1">{equipment?.category}</p>
                      <p className="text-sm font-medium text-primary mt-2">
                        {Number(equipment?.dailyPrice || 0)?.toFixed(2)} EUR / jour
                      </p>
                    </div>
                  </div>

                  <div className="flex items-start gap-3">
                    <Icon name="Calendar" size={20} className="text-primary mt-0.5" />
                    <div className="text-sm">
                      <p className="text-foreground font-medium mb-1">Periode de location</p>
                      <p className="text-muted-foreground">
                        Du {bookingDetails?.startDate ? format(bookingDetails?.startDate, 'dd MMMM yyyy', { locale: fr }) : '-'}
                      </p>
                      <p className="text-muted-foreground">
                        Au {bookingDetails?.endDate ? format(bookingDetails?.endDate, 'dd MMMM yyyy', { locale: fr }) : '-'}
                      </p>
                      <p className="text-foreground font-medium mt-1">
                        {bookingDetails?.rentalDays || 0} jour{(bookingDetails?.rentalDays || 0) > 1 ? 's' : ''}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 pt-4 border-t border-border">
                    <img
                      src={equipment?.owner?.avatar || '/assets/images/no_image.png'}
                      alt={equipment?.owner?.avatarAlt || 'Avatar proprietaire'}
                      className="w-12 h-12 rounded-full object-cover"
                    />
                    <div>
                      <p className="text-sm text-muted-foreground">Proprietaire</p>
                      <p className="font-medium text-foreground">{equipment?.owner?.pseudonym || 'Proprietaire'}</p>
                    </div>
                  </div>
                </div>
              </div>

              <div className="bg-white rounded-lg shadow-elevation-2 p-6">
                <div className="flex items-center gap-3 mb-4">
                  <Icon name="Calculator" size={24} className="text-primary" />
                  <h2 className="text-h4 font-heading text-foreground">
                    Detail des couts
                  </h2>
                </div>
                <CostBreakdown bookingDetails={bookingDetails} />
              </div>

              <div className="bg-white rounded-lg shadow-elevation-2 p-6">
                <div className="flex items-center gap-3 mb-4">
                  <Icon name="CreditCard" size={24} className="text-primary" />
                  <h2 className="text-h4 font-heading text-foreground">
                    Moyen de paiement
                  </h2>
                </div>

                {savedCards?.length > 0 && (
                  <div className="space-y-3 mb-4">
                    {savedCards?.map((card) => (
                      <label
                        key={card?.id}
                        className="flex items-center gap-3 p-4 border border-border rounded-md cursor-pointer hover:border-primary transition-colors"
                      >
                        <input
                          type="radio"
                          name="payment-method"
                          value={card?.id}
                          checked={paymentMethod === card?.id}
                          onChange={(e) => setPaymentMethod(e?.target?.value)}
                          className="w-4 h-4"
                        />
                        <Icon name="CreditCard" size={20} className="text-muted-foreground" />
                        <div className="flex-1">
                          <p className="font-medium text-foreground capitalize">
                            {card?.brand} •••• {card?.last4}
                          </p>
                          <p className="text-sm text-muted-foreground">
                            Expire {card?.expiryMonth?.toString()?.padStart(2, '0')}/{card?.expiryYear}
                          </p>
                        </div>
                      </label>
                    ))}
                  </div>
                )}

                <label className="flex items-center gap-3 p-4 border border-border rounded-md cursor-pointer hover:border-primary transition-colors">
                  <input
                    type="radio"
                    name="payment-method"
                    value="new-card"
                    checked={paymentMethod === 'new-card'}
                    onChange={(e) => setPaymentMethod(e?.target?.value)}
                    className="w-4 h-4"
                  />
                  <Icon name="Plus" size={20} className="text-primary" />
                  <span className="font-medium text-foreground">Nouvelle carte bancaire</span>
                </label>
              </div>

              {paymentMethod === 'new-card' && (
                <div className="bg-white rounded-lg shadow-elevation-2 p-6">
                  {stripeCheckoutEnabled ? (
                    <div className="space-y-4">
                      <div className="flex items-start gap-2 p-3 bg-primary/5 border border-primary/15 rounded-md">
                        <Icon name="ExternalLink" size={18} className="text-primary flex-shrink-0 mt-0.5" />
                        <div className="text-sm">
                          <p className="font-medium text-foreground">Paiement via Stripe (mode test)</p>
                          <p className="text-muted-foreground mt-1">
                            Vous allez etre redirige vers la page securisee Stripe pour saisir la carte test et finaliser le paiement.
                          </p>
                          <p className="text-xs text-muted-foreground mt-2">
                            Exemple carte test Stripe: 4242 4242 4242 4242, date future, CVC libre.
                          </p>
                        </div>
                      </div>

                      <Button
                        type="button"
                        size="lg"
                        fullWidth
                        loading={loading}
                        onClick={handlePayment}
                        className="bg-success hover:bg-success/90 text-success-foreground"
                      >
                        <Icon name="Lock" size={20} className="mr-2" />
                        Payer sur Stripe (test) {Number(bookingDetails?.totalAmount || 0)?.toFixed(2)} EUR
                      </Button>
                    </div>
                  ) : (
                    <PaymentForm
                      onSubmit={handlePayment}
                      loading={loading}
                      totalAmount={bookingDetails?.totalAmount}
                    />
                  )}
                </div>
              )}

              {paymentMethod !== 'new-card' && (
                <Button
                  type="button"
                  size="lg"
                  fullWidth
                  loading={loading}
                  onClick={() => handlePayment({ savedCardId: paymentMethod })}
                  className="bg-success hover:bg-success/90 text-success-foreground"
                >
                  <Icon name="Lock" size={20} className="mr-2" />
                  Confirmer le paiement de {Number(bookingDetails?.totalAmount || 0)?.toFixed(2)} EUR
                </Button>
              )}
            </div>

            <div className="lg:col-span-1">
              <div className="sticky top-24 space-y-6">
                <SecurityBadges />

                <div className="bg-white rounded-lg shadow-elevation-2 p-6">
                  <div className="flex items-center gap-3 mb-3">
                    <Icon name="Shield" size={24} className="text-warning" />
                    <h3 className="text-h5 font-heading text-foreground">
                      Autorisation bancaire (empreinte)
                    </h3>
                  </div>
                  <div className="space-y-3 text-sm">
                    <div className="p-3 bg-warning/10 rounded-md border border-warning/20">
                      <p className="text-foreground font-semibold mb-1">
                        Caution demandee : {Number(bookingDetails?.cautionAmount || 0)?.toFixed(2)} EUR
                      </p>
                      <p className="text-xs text-muted-foreground">(Separe du montant du paiement)</p>
                    </div>
                    <div className="space-y-2">
                      <p className="text-foreground font-medium">Comment ca fonctionne ?</p>
                      <p className="text-muted-foreground">
                        <strong>La caution est une empreinte bancaire temporaire. Elle ne sera prelevee qu'en cas de dommage ou non-restitution.</strong>
                      </p>
                      <p className="text-muted-foreground">
                        Une autorisation sera effectuee sur votre carte, mais aucun debit ne sera realise. L'empreinte sera liberee apres la restitution.
                      </p>
                    </div>
                  </div>
                </div>

                <div className="bg-primary/5 rounded-lg p-6">
                  <div className="flex items-center gap-3 mb-3">
                    <Icon name="HelpCircle" size={24} className="text-primary" />
                    <h3 className="text-h5 font-heading text-foreground">
                      Besoin d'aide ?
                    </h3>
                  </div>
                  <p className="text-sm text-muted-foreground mb-4">
                    Notre equipe est disponible pour repondre a vos questions.
                  </p>
                  <Button variant="outline" size="sm" fullWidth>
                    <Icon name="MessageSquare" size={16} className="mr-2" />
                    Contacter le support
                  </Button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      <Footer />
    </div>
  );
};

export default PaymentProcessing;
